import { useState, useCallback, useEffect, useRef, useMemo } from 'react';
import { GoogleMap, useJsApiLoader, Marker, InfoWindow } from '@react-google-maps/api';
import { Link } from 'react-router-dom';
import './Map.css';

const CENTER = { lat: 34.0522, lng: -118.2437 };

const LOCATIONS = [
  { id: 1,  name: 'Modular Folding Tables',      category: 'Furniture',   quantity: 120, condition: 'Good',     location: 'LA Memorial Coliseum',      lat: 34.0141, lng: -118.2879 },
  { id: 2,  name: 'Athlete Village Bed Frames',  category: 'Furniture',   quantity: 350, condition: 'Like New', location: 'UCLA Olympic Village',       lat: 34.0722, lng: -118.4441 },
  { id: 3,  name: 'LED Stage Lighting Rigs',     category: 'Electronics', quantity: 80,  condition: 'Good',     location: 'Crypto.com Arena',           lat: 34.0430, lng: -118.2673 },
  { id: 4,  name: 'Event Canopy Structures',     category: 'Structures',  quantity: 45,  condition: 'Like New', location: 'Pauley Pavilion, UCLA',      lat: 34.0700, lng: -118.4468 },
  { id: 5,  name: 'Crowd Control Barriers',      category: 'Structures',  quantity: 200, condition: 'Fair',     location: 'Dignity Health Sports Park', lat: 33.8644, lng: -118.2611 },
  { id: 6,  name: 'PA Speaker Systems',          category: 'Electronics', quantity: 30,  condition: 'Good',     location: 'Rose Bowl',                  lat: 34.1614, lng: -118.1676 },
  { id: 7,  name: 'Locker Units (6-Bay)',        category: 'Furniture',   quantity: 60,  condition: 'Like New', location: 'Long Beach Arena',           lat: 33.7701, lng: -118.1937 },
  { id: 8,  name: 'Diesel Portable Generators', category: 'Equipment',   quantity: 25,  condition: 'Good',     location: 'SoFi Stadium',               lat: 33.9535, lng: -118.3392 },
  { id: 9,  name: 'Temporary Bleacher Sections',category: 'Structures',  quantity: 18,  condition: 'Fair',     location: 'USC — Galen Center',         lat: 34.0224, lng: -118.2851 },
  { id: 10, name: 'Broadcast Monitor Displays', category: 'Electronics', quantity: 12,  condition: 'Like New', location: 'SoFi Stadium',               lat: 33.9540, lng: -118.3380 },
];

const CATEGORIES = ['All', ...Array.from(new Set(LOCATIONS.map((l) => l.category)))];

const CATEGORY_COLORS = {
  Furniture:   '#FF0080',
  Electronics: '#1565c0',
  Structures:  '#2e7d32',
  Equipment:   '#e65100',
};

const CONDITION_COLORS = {
  'Like New': '#2e7d32',
  Good:       '#1565c0',
  Fair:       '#e65100',
};

function makeMarkerIcon(category) {
  const fill = CATEGORY_COLORS[category] ?? '#E8008A';
  const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="26" height="38" viewBox="0 0 26 38">
    <path fill="${fill}" stroke="white" stroke-width="1.5"
      d="M13 0C5.82 0 0 5.82 0 13c0 9.75 13 25 13 25S26 22.75 26 13C26 5.82 20.18 0 13 0z"/>
    <circle cx="13" cy="13" r="5" fill="white"/>
  </svg>`;
  return {
    url: `data:image/svg+xml;charset=UTF-8,${encodeURIComponent(svg)}`,
    scaledSize: new window.google.maps.Size(26, 38),
    anchor: new window.google.maps.Point(13, 38),
  };
}

export default function Map() {
  const [selected, setSelected]         = useState(null);
  const [categoryFilter, setCategoryFilter] = useState('All');
  const mapRef = useRef(null);

  useEffect(() => {
    const key = process.env.REACT_APP_GOOGLE_MAPS_API_KEY;
    console.log('[Map] REACT_APP_GOOGLE_MAPS_API_KEY:', key ? `${key.slice(0, 8)}…` : 'UNDEFINED');
  }, []);

  const { isLoaded, loadError } = useJsApiLoader({
    googleMapsApiKey: process.env.REACT_APP_GOOGLE_MAPS_API_KEY,
  });

  const filtered = useMemo(
    () => categoryFilter === 'All'
      ? LOCATIONS
      : LOCATIONS.filter((l) => l.category === categoryFilter),
    [categoryFilter]
  );

  const onMapLoad = useCallback((map) => { mapRef.current = map; }, []);

  const handleMarkerClick = useCallback((loc) => {
    setSelected(loc);
  }, []);

  const handleSidebarClick = useCallback((loc) => {
    setSelected(loc);
    if (mapRef.current) {
      mapRef.current.panTo({ lat: loc.lat, lng: loc.lng });
      mapRef.current.setZoom(14);
    }
  }, []);

  const handleMapClick = useCallback(() => setSelected(null), []);

  if (loadError) return <div className="page">Failed to load Google Maps: {loadError.message}</div>;
  if (!isLoaded)  return <div className="page">Loading map…</div>;

  return (
    <div className="map-page">

      {/* ── Sidebar ── */}
      <aside className="map-sidebar">

        <div className="map-sidebar-header">
          <h1 className="map-sidebar-title">LA28 Surplus<br />Material Locations</h1>
          <p className="map-sidebar-sub">{filtered.length} of {LOCATIONS.length} locations</p>
        </div>

        {/* Category filter */}
        <div className="map-filter-bar">
          {CATEGORIES.map((cat) => (
            <button
              key={cat}
              className={`map-filter-btn${categoryFilter === cat ? ' active' : ''}`}
              style={categoryFilter === cat && cat !== 'All'
                ? { background: CATEGORY_COLORS[cat], borderColor: CATEGORY_COLORS[cat] }
                : {}
              }
              onClick={() => {
                setCategoryFilter(cat);
                setSelected(null);
              }}
            >
              {cat}
            </button>
          ))}
        </div>

        {/* Legend */}
        <div className="map-legend">
          {Object.entries(CATEGORY_COLORS).map(([cat, color]) => (
            <span key={cat} className="legend-item">
              <span className="legend-dot" style={{ background: color }} />
              {cat}
            </span>
          ))}
        </div>

        {/* Scrollable list */}
        <ul className="map-sidebar-list">
          {filtered.map((loc) => (
            <li
              key={loc.id}
              className={`map-sidebar-item${selected?.id === loc.id ? ' active' : ''}`}
              onClick={() => handleSidebarClick(loc)}
            >
              <div className="sidebar-item-row">
                <span
                  className="sidebar-dot"
                  style={{ background: CATEGORY_COLORS[loc.category] ?? '#888' }}
                />
                <span className="sidebar-item-name">{loc.name}</span>
              </div>
              <div className="sidebar-item-meta">
                <span className="sidebar-category">{loc.category}</span>
                <span className="sidebar-quantity">{loc.quantity} units</span>
              </div>
              <div className="sidebar-item-location">{loc.location}</div>
            </li>
          ))}
        </ul>

      </aside>

      {/* ── Map ── */}
      <div className="map-container">
        <GoogleMap
          mapContainerStyle={{ width: '100%', height: '100%' }}
          center={CENTER}
          zoom={11}
          onClick={handleMapClick}
          onLoad={onMapLoad}
          options={{ gestureHandling: 'greedy' }}
        >
          {filtered.map((loc) => (
            <Marker
              key={loc.id}
              position={{ lat: loc.lat, lng: loc.lng }}
              icon={makeMarkerIcon(loc.category)}
              onClick={() => handleMarkerClick(loc)}
            />
          ))}

          {selected && (
            <InfoWindow
              position={{ lat: selected.lat, lng: selected.lng }}
              onCloseClick={() => setSelected(null)}
            >
              <div className="map-infowindow">
                <div className="iw-header">
                  <strong className="iw-name">{selected.name}</strong>
                  <span
                    className="iw-condition"
                    style={{ background: CONDITION_COLORS[selected.condition] }}
                  >
                    {selected.condition}
                  </span>
                </div>
                <div className="iw-row">
                  <span className="iw-label">Category</span>
                  <span className="iw-value">{selected.category}</span>
                </div>
                <div className="iw-row">
                  <span className="iw-label">Quantity</span>
                  <span className="iw-value">{selected.quantity} units</span>
                </div>
                <div className="iw-row">
                  <span className="iw-label">Location</span>
                  <span className="iw-value">{selected.location}</span>
                </div>
                <Link to="/listings" className="iw-btn">View in Listings →</Link>
              </div>
            </InfoWindow>
          )}
        </GoogleMap>
      </div>

    </div>
  );
}
